import React, { useMemo, useState } from "react"
import { Link } from "catalyst-core"
import manifest from "../../generated/docsManifest.json"

/**
 * Hierarchical docs sidebar built from the manifest (which is already in
 * sidebar order). Mirrors Docusaurus's autogenerated sidebar: categories from
 * folder names, collapsible, current page highlighted.
 */
const buildTree = () => {
    // Items keep manifest (sidebar) order, so pages and categories interleave
    // by their numeric prefix exactly like Docusaurus's autogenerated sidebar.
    const root = { label: null, items: [] }
    for (const page of manifest) {
        let node = root
        for (const category of page.categories) {
            let child = node.items.find(
                (item) => item.type === "category" && item.node.label === category
            )?.node
            if (!child) {
                child = { label: category, items: [] }
                node.items.push({ type: "category", node: child })
            }
            node = child
        }
        node.items.push({ type: "page", page })
    }
    return root
}

const Category = ({ node, currentUrl, depth }) => {
    const containsCurrent = useMemo(() => {
        const scan = (candidate) =>
            candidate.items.some((item) =>
                item.type === "page" ? item.page.url === currentUrl : scan(item.node)
            )
        return scan(node)
    }, [node, currentUrl])

    const [open, setOpen] = useState(containsCurrent)

    return (
        <div className={`docs-sidebar-category depth-${depth}`}>
            <button
                className={`docs-sidebar-category-label ${containsCurrent ? "active-trail" : ""}`}
                onClick={() => setOpen(!open)}
                aria-expanded={open}
            >
                <span className={`docs-sidebar-caret ${open ? "open" : ""}`}>›</span>
                {node.label}
            </button>
            {open && <TreeLevel node={node} currentUrl={currentUrl} depth={depth + 1} />}
        </div>
    )
}

const TreeLevel = ({ node, currentUrl, depth }) => (
    <div className="docs-sidebar-level">
        {node.items.map((item) =>
            item.type === "page" ? (
                <Link
                    key={item.page.url}
                    to={item.page.url}
                    className={`docs-sidebar-link ${item.page.url === currentUrl ? "active" : ""}`}
                >
                    {item.page.sidebarLabel}
                </Link>
            ) : (
                <Category key={item.node.label} node={item.node} currentUrl={currentUrl} depth={depth} />
            )
        )}
    </div>
)

const DocsSidebar = ({ currentUrl, mobileOpen, onClose }) => {
    const tree = useMemo(buildTree, [])

    return (
        <>
            {mobileOpen && <div className="docs-sidebar-backdrop" onClick={onClose} role="presentation" />}
            <aside className={`docs-sidebar ${mobileOpen ? "mobile-open" : ""}`}>
                <TreeLevel node={tree} currentUrl={currentUrl} depth={0} />
            </aside>
        </>
    )
}

export default DocsSidebar
